changeSet.sql:
-- Add columns (nullable initially for backfill) ALTER TABLE pull_request_review ADD COLUMN IF NOT EXISTS native_id BIGINT; ALTER TABLE pull_request_review ADD COLUMN IF NOT EXISTS provider_id BIGINT;
-- Backfill native_id: -- Positive IDs (GitHub): native_id = id -- Negative IDs (GitLab approvals via | Long.MIN_VALUE): clear sign bit to restore positive combined ID UPDATE pull_request_review SET native_id = CASE WHEN id >= 0 THEN id ELSE id & x'7FFFFFFFFFFFFFFF'::bigint END WHERE native_id IS NULL;
-- Backfill provider_id from parent pull_request (which is in the issue table via SINGLE_TABLE) UPDATE pull_request_review prr SET provider_id = i.provider_id FROM issue i WHERE prr.pull_request_id = i.id AND prr.provider_id IS NULL;
-- Fallback: any orphaned reviews without a pull_request get GitHub default UPDATE pull_request_review SET provider_id = (SELECT id FROM git_provider WHERE type = 'GITHUB' AND server_url = 'https://github.com') WHERE provider_id IS NULL;
-- Set NOT NULL ALTER TABLE pull_request_review ALTER COLUMN native_id SET NOT NULL; ALTER TABLE pull_request_review ALTER COLUMN provider_id SET NOT NULL;

-- Convert pull_request_review.id to IDENTITY if not already
DO $$
DECLARE maxid BIGINT;
BEGIN
    IF EXISTS (
        SELECT 1 FROM pg_attribute a
        JOIN pg_class c ON a.attrelid = c.oid
        JOIN pg_namespace n ON c.relnamespace = n.oid
        WHERE c.relname = 'pull_request_review'
          AND a.attname = 'id'
          AND a.attidentity = ''
          AND n.nspname = 'public'
    ) THEN
        ALTER TABLE pull_request_review ALTER COLUMN id DROP DEFAULT;
        ALTER TABLE pull_request_review ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY;
    END IF;
    SELECT COALESCE(GREATEST(MAX(id), 0), 0) + 1 FROM pull_request_review INTO maxid;
    EXECUTE format('ALTER TABLE pull_request_review ALTER COLUMN id RESTART WITH %s', maxid);
END $$;

-- Add columns (nullable initially for backfill)
ALTER TABLE label ADD COLUMN IF NOT EXISTS native_id BIGINT;
ALTER TABLE label ADD COLUMN IF NOT EXISTS provider_id BIGINT;

-- Backfill native_id = id (preserves both positive GitHub IDs and negative deterministic IDs)
UPDATE label SET native_id = id WHERE native_id IS NULL;

-- Backfill provider_id from parent repository
UPDATE label l
SET provider_id = r.provider_id
FROM repository r
WHERE l.repository_id = r.id AND l.provider_id IS NULL;

-- Fallback: any orphaned labels without a repository get GitHub default
UPDATE label
SET provider_id = (SELECT id FROM git_provider WHERE type = 'GITHUB' AND server_url = 'https://github.com')
WHERE provider_id IS NULL;

-- Set NOT NULL
ALTER TABLE label ALTER COLUMN native_id SET NOT NULL;
ALTER TABLE label ALTER COLUMN provider_id SET NOT NULL;

-- Convert label.id to IDENTITY if not already
DO $$
DECLARE maxid BIGINT;
BEGIN
    IF EXISTS (
        SELECT 1 FROM pg_attribute a
        JOIN pg_class c ON a.attrelid = c.oid
        JOIN pg_namespace n ON c.relnamespace = n.oid
        WHERE c.relname = 'label'
          AND a.attname = 'id'
          AND a.attidentity = ''
          AND n.nspname = 'public'
    ) THEN
        ALTER TABLE label ALTER COLUMN id DROP DEFAULT;
        ALTER TABLE label ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY;
    END IF;
    SELECT COALESCE(GREATEST(MAX(id), 0), 0) + 1 FROM label INTO maxid;
    EXECUTE format('ALTER TABLE label ALTER COLUMN id RESTART WITH %s', maxid);
END $$;
